package myprovider

import (
	"context"
	"github.com/openmeterio/openmeter/openmeter/app"
)

func NewFactory(appSvc app.Service) *Factory {
	f := &Factory{appSvc: appSvc}
	_ = appSvc.RegisterMarketplaceListing(app.RegistryItem{
		Listing: app.MarketplaceListing{
			Type:         app.AppType("myprovider"),
			Name:         "My Provider",
			Description:  "My billing provider",
			Capabilities: []app.Capability{{Type: app.CapabilityTypeInvoiceCustomers, Key: "invoice", Name: "Invoice", Description: "Invoice customers"}},
			InstallMethods: []app.InstallMethod{app.InstallMethodAPIKey},
		},
		Factory: f,
	})
	return f
}

var _ app.AppFactory = (*Factory)(nil)

func (f *Factory) NewApp(ctx context.Context, base app.AppBase) (app.App, error) {
	return &App{AppBase: base}, nil
}

func (f *Factory) UninstallApp(ctx context.Context, input app.UninstallAppInput) error {
	return nil
}

package billingvalidators

import (
	"context"
	"github.com/openmeterio/openmeter/openmeter/customer"
)

type BillingCustomerValidator struct {
	customer.NoopRequestValidator
	billingAdapter BillingAdapter
}

var _ customer.RequestValidator = (*BillingCustomerValidator)(nil)

func (v *BillingCustomerValidator) ValidateDeleteCustomer(ctx context.Context, input customer.DeleteCustomerInput) error {
	has, err := v.billingAdapter.HasActiveInvoices(ctx, input)
	if err != nil { return err }
	if has { return customer.NewErrDeletingCustomerWithActiveSubscriptions(nil) }
	return nil
}

